use-formeditor-with-document-and-field-r.code:
using Aspose.Pdf;
using Aspose.Pdf.Facades;

Document doc = new Document(inputPath);
using (FormEditor editor = new FormEditor(doc))
{
    foreach (var field in doc.Form.Fields)
    {
        var r = field.Rect;
        float llx = (float)r.LLX + 10f;
        float lly = (float)r.LLY + 15f;
        float urx = (float)r.URX + 10f;
        float ury = (float)r.URY + 15f;
        editor.MoveField(field.Name, llx, lly, urx, ury);
    }
    editor.Save(outputPath);
}

