use-border-and-color-for-listboxfield.code:
foreach (Aspose.Pdf.Forms.ListBoxField listField in document.Form.Fields)
{
    // set border width (and optionally other border properties)
    listField.Border = new Border(listField) { Width = 2 };
    // set border color
    listField.Color = Aspose.Pdf.Color.Blue;
    // set a background‑like color (ListBoxField has no separate background property)
    listField.Color = Aspose.Pdf.Color.LightGray;
}

